// Obtener todos los items
const items = $input.all();

// Fisher-Yates shuffle (mezcla real)
for (let i = items.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [items[i], items[j]] = [items[j], items[i]];
}

// Transformar los datos
return items.map(item => {
  return {
    json: {
      pregunta: `Quieres cobrar este folio?`,
      idrespuesta: item.json.IdParking,
      row: item.json.row_number
    }
  };
});

return items.map(item => {
  const parseFecha = (fecha) => {
    const [dia, mes, anio] = fecha.split("-");
    return new Date(anio, parseInt(mes)-1, dia);
  };

  const fechaEntrada = parseFecha(item.json["Fecha Entrada"]);
  const fechaSalida  = parseFecha(item.json["Fecha Salida"]);

  const precioHora = item.json["Monto Hora"];
  const precioDia  = item.json["Monto Dia"];

  let total = 0;

  // Si la fecha de entrada y salida es la misma → cobrar por horas
  if (fechaEntrada.getTime() === fechaSalida.getTime()) {
    // Convertimos horas exactas
    const parseFechaHora = (fecha, hora) => {
      const [dia, mes, anio] = fecha.split("-");
      const [hrs, min, seg] = hora.split(":");
      return new Date(anio, parseInt(mes)-1, dia, hrs, min, seg);
    };

    const entradaHora = parseFechaHora(item.json["Fecha Entrada"], item.json["Hora Entrada"]);
    const salidaHora  = parseFechaHora(item.json["Fecha Salida"], item.json["Hora Salida"]);

    const diffMs = salidaHora - entradaHora;
    const diffHoras = diffMs / (1000 * 60 * 60);

    total = Math.ceil(diffHoras) * precioHora;

  } else {
    // Fechas distintas → calcular días completos
    const diffMs = fechaSalida - fechaEntrada;
    const dias = Math.ceil(diffMs / (1000 * 60 * 60 * 24)); // diferencia en días
    total = dias * precioDia;
  }

  return {
    json: { total }
  };
});

